export interface QuickbooksSyncSummary {
  /** False when the sync was skipped (lock contended). */
  ran: boolean;
  pulled: number;
  staged: number;
  matched: number;
  /** Newly-staged rows auto-reconciled or auto-minted at high confidence. */
  autoApplied: number;
}

export interface QuickbooksRematchSummary {
  /** False when the rematch was skipped (a sync/rematch was already running). */
  ran: boolean;
  /** Candidate rows examined (pending + unmatched + no donor). */
  scanned: number;
  /** Rows newly given a donor hint by this run. */
  matched: number;
}

export interface QuickbooksReclassifySummary {
  /** False when the reclassify was skipped (a sync/rematch/reclassify was already running). */
  ran: boolean;
  /** Auto-classified pending/excluded rows examined. */
  scanned: number;
  /** Rows newly moved to excluded by this run. */
  excluded: number;
  /** Rows newly restored to pending by this run. */
  included: number;
}

export interface StagedPayment {
  id: string;
  realmId: string;
  qbEntityType: QuickbooksEntityType;
  qbEntityId: string;
  qbLineId?: string | null;
  /** The underlying bank Deposit id this incoming money belongs to, when known. Rows sharing one non-null value are candidates a fundraiser may manually group into a single deposit unit and reconcile as a whole to one multi-allocation gift. Null when not tied to a deposit (or staged before this field existed). */
  qbDepositId?: string | null;
  amount?: string | null;
  dateReceived?: string | null;
  payerName?: string | null;
  payerEmail?: string | null;
  rawReference?: string | null;
  lineDescription?: string | null;
  status: StagedPaymentStatus;
  exclusionReason?: StagedPaymentExclusionReason | null;
  classificationSource: StagedPaymentClassificationSource;
  lineItemNames?: string[] | null;
  lineAccountNames?: string[] | null;
  lineClasses?: string[] | null;
  matchStatus: StagedPaymentMatchStatus;
  matchScore?: number | null;
  matchMethod?: StagedPaymentMatchMethod | null;
  matchConfirmedByUserId?: string | null;
  matchConfirmedAt?: string | null;
  organizationId?: string | null;
  individualGiverPersonId?: string | null;
  householdId?: string | null;
  matchedPaymentIntermediaryId?: string | null;
  matchedGiftId?: string | null;
  createdGiftId?: string | null;
  /** Set on every member of a manually grouped deposit unit that was reconciled as a whole to one existing gift. The group is exactly the rows sharing this gift id; one representative member also carries matchedGiftId. Cleared for the whole group on revert. */
  groupReconciledGiftId?: string | null;
  autoApplied: boolean;
  approvedByUserId?: string | null;
  approvedAt?: string | null;
  rejectedByUserId?: string | null;
  rejectedAt?: string | null;
  queue?: StagedPaymentQueue;
  organizationName?: string | null;
  householdName?: string | null;
  individualGiverPersonName?: string | null;
  intermediaryName?: string | null;
  resolvedGiftId?: string | null;
  resolvedGiftName?: string | null;
  resolvedGiftAmount?: string | null;
  resolvedGiftDate?: string | null;
  /** True when this pending row has no gift of its own, yet every same-donor, similar-amount gift is already linked to a different QuickBooks payment — i.e. the gift for this payment likely hasn't been created yet (create a new gift for it, or exclude if it's a duplicate). */
  giftAlreadyLinkedElsewhere?: boolean;
  createdAt: string;
  updatedAt: string;
}

